		path.addLine(to: CGPoint(x: frame.minX + 0.15936 * frame.width, y: frame.minY + 0.50580 * frame.height))
		path.addLine(to: CGPoint(x: frame.minX + 0.11928 * frame.width, y: frame.minY + 0.45283 * frame.height))
		path.closeSubpath()
		
		return path
	}
}

